mapper.update:
update orders
status = #{status}, pay_status = #{payStatus}, checkout_time = #{checkoutTime}, cancel_reason = #{cancelReason}, rejection_reason = #{rejectionReason}, cancel_time = #{cancelTime}, delivery_time = #{deliveryTime},
where id = #{id}

mapper.select:
select * from orders

    and user_id = #{userId}
    and status = #{status}

order by order_time desc
